using ciceksepetim;
using ciceksepetim.Models;
using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.EntityFrameworkCore;
using System.Collections.Generic;
using System.Linq;

var builder = WebApplication.CreateBuilder(args);

// ------------------------------------
// Hizmet Ekleme (Services Configuration)
// ------------------------------------

// 1. Controller ve View desteği
builder.Services.AddControllersWithViews();

// 2. Veritabanı bağlantısı
builder.Services.AddDbContext<ApplicationDbContext>(options =>
    options.UseSqlServer(builder.Configuration.GetConnectionString("DefaultConnection")));

// 3. Basit Cookie Kimlik Doğrulama (Identity Servisleri YOK)
builder.Services.AddAuthentication(CookieAuthenticationDefaults.AuthenticationScheme)
    .AddCookie(opt =>
    {
        opt.LoginPath = "/Account/Login";
        opt.LogoutPath = "/Account/Logout";
        opt.AccessDeniedPath = "/Account/AccessDenied";
    });

// 4. Yetkilendirme ve Session
builder.Services.AddAuthorization();
builder.Services.AddSession();


var app = builder.Build();

// ------------------------------------
// Middleware Yapılandırması (Pipeline)
// ------------------------------------

if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Home/Error");
    app.UseHsts();
}

app.UseHttpsRedirection();
app.UseStaticFiles();
app.UseRouting();

// Middleware sıralaması aynı kalır
app.UseAuthentication();
app.UseAuthorization();
app.UseSession();

// ------------------------------------
// Veri Besleme (Seeding) - Migration çağrısı yok
// ------------------------------------
using (var scope = app.Services.CreateScope())
{
    var dbContext = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();

    // 1. Kategorileri ekle (sadece boşsa)
    if (!dbContext.Categories.Any())
    {
        var categories = new List<Category>
        {
            new("Çiçek","cicek"),
            new("Yenilebilir Çiçek","yenilebilir"),
            new("Orkide / Saksı","orkide"),
            new("Kek & Çikolata","kek"),
            new("Hediyelik","hediyelik")
        };
        dbContext.Categories.AddRange(categories);
    }

    // 2. Ürünleri ekle (sadece boşsa)
    if (!dbContext.Products.Any())
    {
        var products = new List<Product>
        {
            new Product { Name = "Kırmızı Gül Buketi", Slug = "kirmizi-gul", ImageUrl = "data:image/jpeg;base64,", Price = 799.90m, CategorySlug = "cicek", SellerEmail = "satici@test.com" },
            new Product { Name = "Beyaz Orkide", Slug = "beyaz-orkide", ImageUrl = "data:image/jpeg;base64,", Price = 1299.00m, CategorySlug = "orkide", SellerEmail = "satici@test.com" },
            new Product { Name = "Papatya Aranjman", Slug = "papatya", ImageUrl = "data:image/jpeg;base64,", Price = 449.50m, CategorySlug = "cicek", SellerEmail = "satici@test.com" },
            new Product { Name = "Sukulent Set", Slug = "sukulent", ImageUrl = "data:image/jpeg;base64,", Price = 349.90m, CategorySlug = "orkide", SellerEmail = "satici@test.com" },
            new Product { Name = "Çikolata Kutusu", Slug = "cikolata", ImageUrl = "data:image/jpeg;base64,", Price = 589.90m, CategorySlug = "kek", SellerEmail = "satici@test.com" },
        };
        dbContext.Products.AddRange(products);
    }

    // 3. Değişiklikleri veritabanına kaydet
    dbContext.SaveChanges();
}

app.MapControllerRoute(
    name: "default",
    pattern: "{controller=Home}/{action=Index}/{id?}");

app.Run();